const manifest = loadManifest('monitor/sync-manifest.json');
const writeTargets = scanRepoForWriteTargets({
  prompts: glob('monitor/prompts/**/*.md'),
  scripts: glob('build-scripts/*.js'),
  build: 'build.js',
  agentScripts: glob('monitor/scripts/*.js')
});
const findings = [];
for (const target of writeTargets) {
  const matched = manifest.entries.find(e =>
    e.path === target.path ||
    matchesGlob(e.path, target.path)
  );
  if (!matched) {
    findings.push({
      kind: 'missing-manifest-entry',
      path: target.path,
      writer: target.writer,
      source_file: target.source,
      source_line: target.line,
      severity: 'moderate'
    });
  }
}
