option_c_integration.primary_check_pseudocode:
```js
const manifest = loadManifest('monitor/sync-manifest.json');
const fuseFiles = walkFuse(workspaceRoot, {
  excludePatterns: ['.tmp-*', '.git/', 'node_modules/', '__test_*'],
  excludeDirs: ['monitor/integrity/workspace-sync-runs/']  // append-only, fast-growing
});
const findings = [];
for (const f of fuseFiles) {
  const fuseMTime = stat(f).mtime;
  const mainMTime = await getMainCommitTime(f);
  const entry = matchManifest(manifest, f);
  if (!entry) {
    if (fuseMTime > mainMTime || mainMTime === null) {
      findings.push({
        kind: 'manifest-gap-candidate',
        path: f,
        fuse_mtime: fuseMTime,
        main_mtime: mainMTime,
        severity: 'moderate'
      });
    }
  } else if (entry.direction === 'clone_to_workspace' && fuseMTime > mainMTime) {
    findings.push({
      kind: 'direction-violation',
      path: f,
      manifest_direction: entry.direction,
      fuse_mtime: fuseMTime,
      main_mtime: mainMTime,
      severity: 'moderate'
    });
  } else if (entry.direction === 'never' && entry.classification === 'scratch' && entry.deprecation_at) {
    if (Date.now() > Date.parse(entry.deprecation_at)) {
      findings.push({
        kind: 'relic-deprecation-due',
        path: f,
        severity: 'low'
      });
    }
  }
}
```
